import constructFence from './index';

describe('Javascript - Medium - 38', () => {
  test('The Million Dollar Fence', () => {
    expect(constructFence('$50,000')).toBe('HHHHHHHHHHHHHHHHHHHH');
    expect(constructFence('$100,000')).toBe('HHHHHHHHHH');
    expect(constructFence('$1,000,000')).toBe('H');
    expect(constructFence('$500,000')).toBe('HH');
    expect(constructFence('$20,000')).toBe(
      'HHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHH'
    );
    expect(constructFence('$10,000')).toBe(
      'HHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHH'
    );
    expect(constructFence('$5000')).toBe(
      'HHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHHH'
    );
    expect(constructFence('$1000')).toBe(
      ''
    );
  });
});
